solute; transition: transform var(--d-t, 0.3s) var(--d-t-e, ease), opacity var(--d-o, 0.2s); } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:checked { --b: var(--active); --bc: var(--active); --d-o: 0.3s; --d-t: 0.6s; --d-t-e: cubic-bezier(0.2, 0.85, 0.32, 1.2); } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:focus { box-shadow: 0 0 0 var(--focus); } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:not(.switch) { width: 18px; height: 18px; } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:not(.switch):after { opacity: var(--o, 0); } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:not(.switch):checked { --o: 1; } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:not(.switch) { border-radius: 7px; } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:not(.switch):after { width: 5px; height: 9px; border: 2px solid var(--active-inner); border-top: 0; border-left: 0; left: 6px; top: 2px; transform: rotate(var(--r, 20deg)); } .bspdGdprCheckboxWrapper input[type=&apos;checkbox&apos;]:not(.switch):checked { --r: 43deg; } } .bspdGdprCheckboxWrapper *:before, .bspdGdprCheckboxWrapper *:after { box-sizing: inherit; }
