;  value=&amp;quot;+263&amp;quot;&amp;gt;🇿🇼 +263&amp;lt;/option&amp;gt;&amp;lt;option style=&amp;quot;color : black;&amp;quot;  value=&amp;quot;+358&amp;quot;&amp;gt;🇦🇽 +358&amp;lt;/option&amp;gt;
