                  &lt;script&gt;
function getBspdBarCookie(name) {
  const value = &quot;; &quot; + document.cookie;
  const parts = value.split(&quot;; &quot; + name + &quot;=&quot;);
  if (parts.length === 2) {
    return parts.pop().split(&quot;;&quot;).shift();
  }
  return null;
}

function setBspdBarCookie(name, value, days) {
  const expires = new Date();

  expires.setTime(expires.getTime() + days * 24 * 60 * 60 * 1000);
  document.cookie = name + &quot;=&quot; + value + &quot;;expires=&quot; + expires.toUTCString() + &quot;;path=/&quot;;
}

// helper function to delete a cookie
function deleteBspdBarCookie(name) {
  document.cookie = name + &quot;=;expires=Thu, 01 Jan 1970 00:00:00 UTC;path=/&quot;;
}

// get end date based on timer type
const getEndDate = (cookieKey, timer) =&gt; {
  const now = new Date();

  const timerType = timer.dataset.timerType;
  const dateTime = timer.dataset.timerDatetime;
  const days = parseInt(timer.dataset.timerDays) || 0;
  const hours = parseInt(timer.dataset.timerHours) || 0;
  const minutes = parseInt(timer.dataset.timerMinutes) || 0;
  const seconds = parseInt(timer.dataset.timerSeconds) || 0;

  if (timerType === &quot;Static Date &amp; Time&quot;) {
    const endDate = new Date(dateTime);
    setBspdBarCookie(cookieKey, endDate.getTime());
    return endDate;
  }

  if (timerType === &quot;Relative&quot;) {
    const stored = getBspdBarCookie(cookieKey);
    if (stored) return new Date(parseInt(stored));

    const endDate = new Date(now.getTime() + days * 86400000 + hours * 3600000 + minutes * 60000 + seconds * 1000);
    setBspdBarCookie(cookieKey, endDate.getTime());
    return endDate;
  }

  if (timerType === &quot;Daily&quot;) {
    const stored = getBspdBarCookie(cookieKey);
    const midnight = new Date();
    midnight.setHours(24, 0, 0, 0);

    if (stored) {
      const storedDate = new Date(parseInt(stored));
      if (storedDate.toDateString() === midnight.toDateString()) {
        return storedDate;
      }
    }

    setBspdBarCookie(cookieKey, midnight.getTime());
    return midnight;
  }

  return null;
};

let interval = null;
// Main timer function
const startTimer = (timer) =&gt; {
  const timerType = timer.dataset.timerType;
  const popupId = timer.dataset.popupId;
  const cookieKey = &quot;endDate_&quot; + timerType + popupId;
  const endDate = getEndDate(cookieKey, timer);

  if (!endDate) return null;

  const update = () =&gt; {
    const now = Date.now();
    const remaining = endDate.getTime() - now;

    if (remaining &lt;= 0) {
      updateDisplay(0, 0, 0, 0);
      if (timerType === &quot;Daily&quot;) {
        setTimeout(() =&gt; {
          deleteBspdBarCookie(cookieKey);
        }, 1000);
      }

      return clearInterval(interval);
    }

    const days = Math.floor(remaining / 86400000);
    const hours = Math.floor((remaining % 86400000) / 3600000);
    const minutes = Math.floor((remaining % 3600000) / 60000);
    const seconds = Math.floor((remaining % 60000) / 1000);

    updateDisplay(days, hours, minutes, seconds);
  };

  const updateDisplay = (days, hours, minutes, seconds) =&gt; {
    const pad = (n) =&gt; n.toString().padStart(2, &quot;0&quot;);

    const dayElement = timer.querySelector(&quot;.timer-unit-days .timer-number&quot;);
    const hourElement = timer.querySelector(&quot;.timer-unit-hours .timer-number&quot;);
    const minuteElement = timer.querySelector(&quot;.timer-unit-minutes .timer-number&quot;);
    const secondElement = timer.querySelector(&quot;.timer-unit-seconds .timer-number&quot;);

    if (dayElement) {
      dayElement.textContent = pad(days);
    }
    if (hourElement) {
      hourElement.textContent = pad(hours);
    }
    if (minuteElement) {
      minuteElement.textContent = pad(minutes);
    }
    if (secondElement) {
      secondElement.textContent = pad(seconds);
    }
  };

  update();
  interval = setInterval(update, 1000);
};

document.querySelectorAll(&quot;#timer-container-3708580763402240&quot;).forEach((timer) =&gt; {
  // select all timers and start them
  startTimer(timer);
});
&lt;/script&gt;
